const dataString = context.item.data?.['Primeiro contato']?.[0];
if (!dataString) return "-";

const data = new Date(dataString);
const agora = new Date();

// Zerar horário para comparar apenas o dia
const diaData = new Date(data.getFullYear(), data.getMonth(), data.getDate());
const diaHoje = new Date(agora.getFullYear(), agora.getMonth(), agora.getDate());

const diffDias = (diaHoje - diaData) / (1000 * 60 * 60 * 24);

// Nome dos dias (WhatsApp usa nomes curtos)
const diasSemana = ["Dom", "Seg", "Ter", "Qua", "Qui", "Sex", "Sáb"];

// Início da semana (segunda-feira)
const inicioSemana = new Date(diaHoje);
inicioSemana.setDate(
    diaHoje.getDate() - (diaHoje.getDay() === 0 ? 6 : diaHoje.getDay() - 1)
);

// --- REGRAS WHATSAPP ---

// Hoje
if (diffDias === 0) {
    return data.toLocaleTimeString("pt-BR", {
        hour: "2-digit",
        minute: "2-digit"
    });
}

// Ontem
if (diffDias === 1) {
    return "Ontem";
}

// Mesma semana (mas não ontem)
if (diaData >= inicioSemana) {
    return diasSemana[data.getDay()];
}

// Mesmo ano → “05/12”
if (data.getFullYear() === agora.getFullYear()) {
    return data.toLocaleDateString("pt-BR", { day: "2-digit", month: "2-digit" });
}

// Ano diferente → “05/12/2024”
return data.toLocaleDateString("pt-BR");

